    // Wait for results to update
    await waitForResults(page)

    // URL should contain page=2
    await expect(page).toHaveURL(/[?&]page=2/)

    // Summary text should show a different range (e.g., "Showing 21–40" instead of "Showing 1–20")
    const summaryAfter = await page.getByText(/Showing \d+[–-]\d+ of/i).textContent()
    expect(summaryAfter).not.toBe(summaryBefore)
  })

  test('change page size updates results per page and resets to page 1 @standard @pagination', async ({
    page,
  }) => {
    // Start on page 2 so we can verify reset
    await searchWith(page, { page: '2' })
    await waitForResults(page)

    // Change page size via the "Per page" select
    const pageSizeSelect = page.getByLabel('Per page')
    await pageSizeSelect.selectOption('5')

    // Wait for results to update
    await waitForResults(page)

    // URL should have pageSize=5 and page should be reset (no page param or page=1)
    const url = page.url()
    expect(url).toContain('pageSize=5')
    expect(url).not.toMatch(/[?&]page=/)

    // Summary should show at most 5 results in the range
    const summary = await page.getByText(/Showing \d+[–-]\d+ of/i).textContent()
    expect(summary).not.toBeNull()
    const rangeMatch = summary!.match(/Showing (\d+)[–-](\d+)/)
